#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, "../..");
const metricsPath = path.join(
  repoRoot,
  ".ai-tasks/entropy/entropy-metrics.json",
);
const sprintPath = path.join(repoRoot, ".ai-tasks/entropy/entropy-sprint-1.md");

/**
 * Reads metrics generated by entropy dashboard job.
 * @returns {{generatedAt: string, fileCount: number, aiTempCount: number, govExceptionCount: number, hardLimitFiles: Array<{relPath: string, lineCount: number}>, softLimitFiles: Array<{relPath: string, lineCount: number}>, wrapperLikeNames: string[]}}
 */
function readEntropyMetrics() {
  if (!fs.existsSync(metricsPath)) {
    throw new Error(
      `missing entropy metrics: ${path.relative(repoRoot, metricsPath)}; run pnpm governance:entropy-report first`,
    );
  }
  return JSON.parse(fs.readFileSync(metricsPath, "utf8"));
}

/**
 * Creates sprint tasks from top hard-limit hotspots.
 * @param {{hardLimitFiles: Array<{relPath: string, lineCount: number}>, aiTempCount: number, wrapperLikeNames: string[]}} metrics Entropy metrics payload.
 */
function buildSprintPlan(metrics) {
  const topHard = metrics.hardLimitFiles.slice(0, 5);

  const lines = [
    "# Entropy Sprint 1",
    "",
    `Generated from: .ai-tasks/entropy/entropy-metrics.json`,
    `Generated at: ${new Date().toISOString()}`,
    "",
    "## Scope",
    "",
    "- Target top 5 hard-limit files by line count.",
    "- Keep mutation radius inside each owning module.",
    "- No behavior changes unless explicitly required by tests/contracts.",
    "",
    "## Goals",
    "",
    "1. Reduce hard-limit file count by at least 3 files.",
    "2. Ensure every extracted file has explicit ownership intent comments.",
    "3. Preserve governance check compatibility for touched scope.",
    "",
    "## Backlog",
    "",
  ];

  if (topHard.length === 0) {
    lines.push("- No hard-limit hotspots found; close sprint.");
  } else {
    topHard.forEach((item, index) => {
      lines.push(`### Task ${index + 1}`);
      lines.push("");
      lines.push(`- Target file: ${item.relPath}`);
      lines.push(`- Current line count: ${item.lineCount}`);
      lines.push(
        "- Action: split by ownership boundary into 2-4 cohesive modules.",
      );
      lines.push(
        "- Guardrails: preserve public contracts and remove replaced code in same batch.",
      );
      lines.push(
        "- Validation: pnpm governance:file-shape -- --changed && pnpm governance:check",
      );
      lines.push("");
    });
  }

  lines.push("## Risk Controls", "");
  lines.push(`- AI-TEMP current count: ${metrics.aiTempCount}`);
  lines.push(
    `- Wrapper-like filename count: ${metrics.wrapperLikeNames.length}`,
  );
  lines.push(
    "- Any new AI-TEMP requires explicit burn-down owner and removal condition.",
  );
  lines.push("- Do not introduce parallel implementation tracks.");
  lines.push("");

  lines.push("## Exit Criteria", "");
  lines.push(
    "1. At least 3 targeted files reduced below hard limit (<=600 lines).",
  );
  lines.push(
    "2. No new governance hard failures introduced by sprint changes.",
  );
  lines.push("3. Entropy dashboard regenerated and trend documented.");
  lines.push("");

  return lines.join("\n");
}

/**
 * Writes sprint plan markdown to .ai-tasks/entropy.
 */
function writeSprintPlan() {
  const metrics = readEntropyMetrics();
  const plan = buildSprintPlan(metrics);
  fs.mkdirSync(path.dirname(sprintPath), { recursive: true });
  fs.writeFileSync(sprintPath, plan, "utf8");
  console.log(`[entropy-sprint] ok -> ${path.relative(repoRoot, sprintPath)}`);
}

writeSprintPlan();
